#include <bits/stdc++.h>
using namespace std;

long long n, s;
long long tmp = 0;
long long MAX = 1e12;

int main() {
    cin >> n >> s;
    getchar();
    for (int i = 0; i < n; i++) {
        char c = getchar();
        switch (c) {
            case 'U':
                if (s == 1) continue;
                if (tmp)
                    tmp--;
                else
                    s /= 2;
                break;
            case 'L':
                if (2 * s > MAX)
                    tmp++;
                else 
                    s = 2 * s;
                break;
            case 'R':
                if (2 * s + 1 > MAX)
                    tmp++;
                else 
                    s = 2 * s + 1;
                break;
        }
    }
    cout << s;
    return 0;
}
